// @ts-check

import { AbstractHandler } from './AbstractHandler.js'

/**
 * @typedef {import('../../utils/Command.js').Command} Command
 */

class SetStaticFieldHandler extends AbstractHandler {
    requiredParametersCount = 3

    constructor() {
        super()
    }

    /**
     * @param {Command} command
     */
    process(command) {
        try {
            this.validate(command, this.requiredParametersCount, this.constructor.name)
            const { payload } = command
            let [type, field, value] = payload
            if (typeof type[field] === 'undefined') {
                let fields = Object.keys(type)
                let message = `Field ${field} not found in class ${type.constructor.name}. Available fields:\n`
                fields.forEach((fieldIter) => {
                    message += `${fieldIter}\n`
                })
                throw new Error(message)
            }
            type[field] = value
            return type
        } catch (error) {
            throw this.process_stack_trace(error, this.constructor.name)
        }
    }
}

export { SetStaticFieldHandler }
